/* ═══ HOLOGRAPHIC KEYFRAMES ═══════════════════════════════════ */

/* Entry: smooth beam expansion with gentle glow — satisfying, not frantic */
@keyframes holo-materialize-4f42542f {
0% {
    clip-path: inset(48% 30% 48% 30%);
    opacity: 0;
    filter: brightness(2.5) saturate(0) blur(2px);
    transform: translateX(-50%) scale(0.97);
}
15% {
    opacity: 1;
    filter: brightness(2) saturate(0.2) blur(0.5px);
    clip-path: inset(40% 10% 40% 10%);
}
35% {
    clip-path: inset(20% 3% 20% 3%);
    filter: brightness(1.4) saturate(0.5) blur(0px);
    transform: translateX(-50%) scale(0.99);
}
60% {
    clip-path: inset(5% 0% 5% 0%);
    filter: brightness(1.15) saturate(0.85);
}
80% {
    clip-path: inset(1% 0% 1% 0%);
    filter: brightness(1.05) saturate(0.95);
    transform: translateX(-50%) scale(1);
}
100% {
    clip-path: inset(0);
    opacity: 1;
    filter: brightness(1) saturate(1) blur(0px);
    transform: translateX(-50%) scale(1);
}
}

/* Scan beam sweeps top → bottom during materialization */
@keyframes holo-scanbeam-4f42542f {
0%   { top: 0%;   opacity: 0.9; height: 2px;
}
40%  { opacity: 1; height: 3px;
}
100% { top: 100%; opacity: 0;   height: 1px;
}
}

/* Scanline texture drifts upward slowly (CRT / hologram feel) */
@keyframes holo-scanline-drift-4f42542f {
0%   { background-position: 0 0;
}
100% { background-position: 0 -40px;
}
}

/* Edge glow pulses after materialization */
@keyframes holo-edge-breathe-4f42542f {
0%, 100% { opacity: 0.2;
}
50%      { opacity: 0.6;
}
}

/* Icon resolves from static */
@keyframes holo-icon-stabilize-4f42542f {
0%   { opacity: 0; transform: scale(1.8); filter: blur(4px) drop-shadow(0 0 12px currentColor);
}
40%  { opacity: 1; transform: scale(0.9); filter: blur(0px) drop-shadow(0 0 8px currentColor);
}
60%  { transform: scale(1.1);
}
80%  { transform: scale(0.97);
}
100% { transform: scale(1); filter: drop-shadow(0 0 6px currentColor);
}
}

/* Retry text materializes late */
@keyframes holo-retry-fade-in-4f42542f {
0%   { opacity: 0; transform: translateX(-4px); filter: blur(2px);
}
60%  { opacity: 0.8; filter: blur(0);
}
100% { opacity: 0.65; transform: translateX(0);
}
}

/* Exit: smooth fade and collapse — graceful, not frantic */
@keyframes holo-destabilize-4f42542f {
0% {
    clip-path: inset(0);
    opacity: 1;
    filter: brightness(1) saturate(1);
    transform: translateX(-50%) scale(1);
}
30% {
    clip-path: inset(5% 2% 5% 2%);
    opacity: 0.8;
    filter: brightness(1.3) saturate(0.5);
    transform: translateX(-50%) scale(0.99);
}
60% {
    clip-path: inset(25% 8% 25% 8%);
    filter: brightness(1.8) saturate(0.2) blur(0.5px);
    opacity: 0.5;
}
85% {
    clip-path: inset(42% 20% 42% 20%);
    filter: brightness(2.2) saturate(0) blur(1px);
    opacity: 0.2;
}
100% {
    clip-path: inset(50% 40% 50% 40%);
    filter: brightness(2.5) saturate(0) blur(2px);
    opacity: 0;
    transform: translateX(-50%) scale(0.98);
}
}

